using System;
using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// Build the test data
var rng = new Random(42);
var sampleWords = new[]
{
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "benchmark", "performance", "analysis", "framework", "application",
    "extraordinary", "implementation", "infrastructure", "a", "I",
    "to", "is", "of", "in", "it", "on", "at", "by", "an", "or",
    "documentation", "internationalization", "characteristically"
};
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
    words[i] = sampleWords[rng.Next(sampleWords.Length)];

var text = string.Join(' ', words);
var analyzer = new TextAnalyzer(text);

